2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - Next Generation", () => {
6	  it("should return an empty array for an empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should let a single live cell die (underpopulation)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should let two neighboring cells die, each having only one live neighbor (underpopulation)", () => {
13	    expect(
14	      nextGeneration([
15	        [0, 1],
16	        [1, 1],
17	      ])
18	    ).toEqual([]);
19	  });
20	  it("should keep a live cell with three live neighbors alive (survival)", () => {
21	    expect(
22	      nextGeneration([
23	        [0, 0],
24	        [1, 0],
25	        [2, 0],
26	        [1, 1],
27	      ])
28	    ).toContainEqual([1, 1]);
29	  });
30	  it("should let a live cell with four live neighbors die (overpopulation)", () => {
31	    expect(
32	      nextGeneration([
33	        [0, 0],
34	        [0, 1],
35	        [0, 2],
36	        [1, 0],
37	        [1, 1],
38	      ])
39	    ).not.toContainEqual([1, 1]);
40	  });
